import React, { useEffect, useRef, useState } from "react"
import Seo from "../components/seo"
import data from "../datasheet/wallpaper.yml"
import "fontsource-roboto"
import { CssBaseline } from "@mui/material"
import gradientStyle from "!raw-loader!../css/gradient.css"

import ColorPanel from "../components/gradient/colorsetting"
import { Helmet } from "react-helmet"

const Wallpaper = () => {
  const canvas = useRef(null)
  const [stop1, setStop1] = useState("#336375")
  const [stop2, setStop2] = useState("#333333")
  const [where, setWhere] = useState([0, 0])
  const [globalOpacity, setGlobalOpacity] = useState(100)
  const [globalOpacityID, setGlobalOpacityID] = useState()
  const [globalOpacityArray, setGlobalOpacityArray] = useState([])
  const [composite, setComposite] = useState("source-over")

  const fillGrad = (
    wall,
    x0,
    y0,
    x1,
    y1,
    stop1,
    stop2,
    opacity = 100,
    composite = "source-over"
  ) => {
    if (x0 === x1 && y0 === y1) {
      return
    }
    const ctx = wall.getContext("2d")

    if (ctx.globalCompositeOperation !== composite) {
      ctx.globalCompositeOperation = composite
    }

    const w = wall.clientWidth
    const h = wall.clientHeight
    if (wall.width !== w || wall.height !== h) {
      // TODO: fix pixels content disappearing problem
      wall.width = w
      wall.height = h
    }

    const grd = ctx.createLinearGradient(x0, y0, x1, y1)
    var opacity_hex = parseInt(opacity * 2.55).toString(16)
    if (opacity_hex.length === 1) {
      opacity_hex = "0" + opacity_hex
    }
    grd.addColorStop(0, `${stop1}${opacity_hex}`)
    grd.addColorStop(1.0, `${stop2}${opacity_hex}`)
    // grd.addColorStop(0, `rgba(0,0,0,1.0)`)
    // grd.addColorStop(1.0, `rgba(0,255,0,0.1)`)
    ctx.fillStyle = grd
    ctx.fillRect(0, 0, wall.width, wall.height)
  }

  useEffect(() => {
    const w = canvas.current.clientWidth
    const h = canvas.current.clientHeight
    canvas.current.width = w
    canvas.current.height = h
    fillGrad(canvas.current, 0, 0, w, h, "#336375", "#333333")
  }, [])

  const handleKey = e => {
    if ((e.key || "") in "0123456789".split("")) {
      const newArray = [...globalOpacityArray, e.key]
      setGlobalOpacityArray([...globalOpacityArray, e.key])
      if (newArray.length < 2) {
        newArray.push("0")
      }
      setGlobalOpacity(
        Number(newArray.slice(Math.max(newArray.length - 2, 0)).join("")) || 100
      )
      if (globalOpacityID) {
        clearTimeout(globalOpacityID)
        setGlobalOpacityID(null)
      }
      const timeID = setTimeout(() => {
        setGlobalOpacityArray([])
      }, 1000)
      setGlobalOpacityID(timeID)
    }
  }

  const DrawHandle = (x0, y0, x1, y1, stop1, stop2, clear = false) => {
    const canvas = document.getElementById("canvas-handle")
    const w = canvas.clientWidth
    const h = canvas.clientHeight
    if (canvas.width !== w || canvas.height !== h || clear) {
      // TODO: fix pixels content disappearing problem
      canvas.width = w
      canvas.height = h
      if (clear) {
        return
      }
    }
    const ctx = canvas.getContext("2d")
    ctx.globalCompositeOperation = "copy"
    ctx.stroke()
    ctx.globalCompositeOperation = "source-over"

    ctx.shadowColor = "rgba(0, 0, 0, .5)"
    ctx.shadowBlur = 8

    ctx.strokeStyle = "#eee"
    ctx.lineWidth = 4

    ctx.beginPath()
    ctx.moveTo(x0, y0)
    ctx.lineTo(x1, y1)
    ctx.stroke()

    // ctx.lineWidth = 3
    // ctx.strokeStyle = '#666'
    // ctx.beginPath();
    // ctx.moveTo(x0, y0);
    // ctx.lineTo(x1, y1);
    // ctx.stroke();

    ctx.lineWidth = 6
    ctx.beginPath()
    ctx.ellipse(x0, y0, 5, 5, 0, 0, Math.PI * 2)
    ctx.stroke()
    ctx.fillStyle = stop1
    ctx.fill()

    ctx.beginPath()
    ctx.ellipse(x1, y1, 5, 5, 0, 0, Math.PI * 2)
    ctx.stroke()
    ctx.fillStyle = stop2
    ctx.fill()
  }

  return (
    <>
      <Seo {...data.SEO} />
      <Helmet>
        <style>{gradientStyle}</style>
      </Helmet>
      <CssBaseline />
      <ColorPanel
        {...{
          stop1,
          stop2,
          setStop1,
          setStop2,
          setGlobalOpacity,
          globalOpacity,
          globalOpacityArray,
          composite,
          setComposite,
        }}
      />
      <canvas id="wallpaper" ref={canvas} className="gradient-canvas" />
      <canvas
        id="canvas-handle"
        tabIndex={0}
        className="gradient-canvas"
        onMouseDown={e => {
          setWhere([e.clientX, e.clientY])
        }}
        onMouseMove={e => {
          if (e.buttons === 1) {
            if (where.length === 2) {
              DrawHandle(...where, e.clientX, e.clientY, stop1, stop2)
            }
          }
        }}
        onMouseUp={e => {
          if (where.length === 2) {
            fillGrad(
              canvas.current,
              ...where,
              e.clientX,
              e.clientY,
              stop1,
              stop2,
              globalOpacity,
              composite
            )
          }
          DrawHandle(0, 0, 0, 0, 0, 0, true)
          setWhere([])
        }}
        onKeyUp={handleKey}
      />
    </>
  )
}

export default Wallpaper
